Javascript.miscCode:
		function SelectHearingDate_Popup(){}
		SelectHearingDate_Popup.nextFocusedAdaptorId = function() {
			return 'N39ServiceDate'; } 
		  
		SelectHearingDate_Popup.raise = {
			eventBinding: {
				singleClicks: [ {element: "N39HearingDateLOVBtn"} ],
				keys: [ { key: Key.F6, element: "N39HearingDate" } ] } };
			
		SelectHearingDate_Popup.lower = {
			eventBinding: {
				singleClicks: [ {element: "SelectHearingDate_CancelBtn"} ],
				keys: [ { key: Key.F4, element: "SelectHearingDate_Popup" } ]
			}
		};
        
		function N39HearingDateLOVBtn() {}
		N39HearingDateLOVBtn.tabIndex = __tabIdx++;
			
		function SelectHearingDate_OKBtn(){}
		SelectHearingDate_OKBtn.actionBinding = function() { 	
			var hid = Services.getValue(SelectHearingDateGrid.dataBinding);
			var dateSel = Services.getValue("/ds/MaintainHearing/Hearings/Hearing[./HearingID = '"+hid+"']/Date");                
			Services.setValue(N39HearingDate.dataBinding, dateSel);				
			FormController.getInstance().hideFormExtensionPopup("SelectHearingDate"); }
			
		SelectHearingDate_OKBtn.additionalBindings = {
			eventBinding: {
				doubleClicks: [ {element: "SelectHearingDateGrid"} ]
			}
		};
			
		function SelectHearingDate_CancelBtn(){}
		
		function SelectHearingDateGrid(){}
		SelectHearingDateGrid.dataBinding = "/ds/EnterVariableData/Service/selectHearingGrid";
		SelectHearingDateGrid.helpText = "Select the hearing venue";
		SelectHearingDateGrid.srcData	= "/ds/MaintainHearing/Hearings"; 
		SelectHearingDateGrid.keyXPath  = "HearingID";
		SelectHearingDateGrid.rowXPath	= "Hearing";   
		SelectHearingDateGrid.columns = [
			{xpath: "VenueCode"},
			{xpath: "VenueName"},
			{xpath: "TypeOfHearing"},
			{xpath: "Date", sort: CaseManUtils.sortGridDatesDsc, defaultSort:"true", defaultSortOrder:"descending", transformToDisplay: CaseManUtils.formatGridDate},
			{xpath: "Time",  transformToDisplay: CaseManUtils.convertSecondsToTime}  ];

Context.isEnabled:
if(IsNewN79AsReqd.isEnabled()) {
  	if( 'Y' == Services.getValue(IsNewN79AsReqd.dataBinding)) {
		return true; }
	return false; }
return true;

